#include <vector>
#include <unordered_map>

using namespace std;

long long solve(vector<long long> nums, long long k) {
    unordered_map<long long, long long> prefixMod;
    prefixMod[0] = -1;
    long long sum = 0;
    vector<pair<long long, long long>> segments;

    for (long long i = 0; i < nums.size(); ++i) {
        sum += nums[i];
        long long mod = (sum % k + k) % k;
        if (prefixMod.count(mod)) {
            segments.emplace_back(prefixMod[mod] + 1, i);
        }
        prefixMod[mod] = i;
    }

    // Merge overlapping or adjacent segments
    if (segments.empty()) {
        return sum;
    }

    sort(segments.begin(), segments.end());
    vector<pair<long long, long long>> merged;
    for (auto &seg : segments) {
        if (merged.empty() || seg.first > merged.back().second) {
            merged.push_back(seg);
        } else {
            merged.back().second = max(merged.back().second, seg.second);
        }
    }

    long long totalRemoved = 0;
    for (auto &seg : merged) {
        long long segSum = 0;
        for (long long i = seg.first; i <= seg.second; ++i) {
            segSum += nums[i];
        }
        totalRemoved += segSum;
    }

    return sum - totalRemoved;
}
